import React, { useState } from "react";

import Layout from "../components/Layout";

import {
    Typography,
    Card,
    CardContent,
    TextField,
    Button,
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableRow,
    Grid
} from "@mui/material";

import {
    getDevices,
    saveDevices
} from "../data/deviceStorage";

function Devices() {

    const [deviceName, setDeviceName] = useState("");
    const [deviceType, setDeviceType] = useState("");
    const [imei, setImei] = useState("");
    const [location, setLocation] = useState("");

    const [devices, setDevices] =
        useState(getDevices());

    const updateDevices = (updatedDevices) => {
        setDevices(updatedDevices);
        saveDevices(updatedDevices);
    };

    const addDevice = () => {

        if (
            !deviceName ||
            !deviceType ||
            !imei ||
            !location
        ) {
            alert("Please fill all fields");
            return;
        }

        const nextId =
            devices.length > 0
                ? Math.max(...devices.map(d => d.id)) + 1
                : 1;

        const newDevice = {
            id: nextId,
            name: deviceName,
            type: deviceType,
            imei: imei,
            status: "Online",
            location: location
        };

        const updatedDevices = [
            ...devices,
            newDevice
        ];

        updateDevices(updatedDevices);

        setDeviceName("");
        setDeviceType("");
        setImei("");
        setLocation("");
    };

    const deleteDevice = (id) => {

        const updatedDevices =
            devices.filter(
                device => device.id !== id
            );

        updateDevices(updatedDevices);
    };

    const toggleStatus = (id) => {

        const updatedDevices =
            devices.map(device =>
                device.id === id
                    ? {
                        ...device,
                        status:
                            device.status === "Online"
                                ? "Offline"
                                : "Online"
                    }
                    : device
            );

        updateDevices(updatedDevices);
    };

    return (
        <Layout>

            <Typography
                variant="h4"
                gutterBottom
            >
                IoT Device DB Management
            </Typography>

            <Typography
                variant="subtitle1"
                color="primary"
            >
                Device Registration • Inventory • Lifecycle Management
            </Typography>

            <Typography
                variant="body2"
                color="text.secondary"
                sx={{ mb: 4 }}
            >
                Create, monitor, update and manage connected
                IoT devices across the 5G AF platform.
            </Typography>

            <Card sx={{ mb: 3 }}>
                <CardContent>

                    <Typography variant="h6">
                        Add New IoT Device
                    </Typography>

                    <Typography
                        variant="body2"
                        color="text.secondary"
                    >
                        Register and manage IoT devices.
                    </Typography>

                    <br />

                    <Grid container spacing={2}>

                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Device Name"
                                value={deviceName}
                                onChange={(e) =>
                                    setDeviceName(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <TextField
                                fullWidth
                                label="Device Type"
                                value={deviceType}
                                onChange={(e) =>
                                    setDeviceType(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="IMEI Number"
                                value={imei}
                                onChange={(e) =>
                                    setImei(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <TextField
                                fullWidth
                                label="Location"
                                value={location}
                                onChange={(e) =>
                                    setLocation(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <Button
                                fullWidth
                                variant="contained"
                                sx={{ height: "56px" }}
                                onClick={addDevice}
                            >
                                Add Device
                            </Button>
                        </Grid>

                    </Grid>

                </CardContent>
            </Card>

            <Card>
                <CardContent>

                    <Typography variant="h6">
                        IoT Device Database
                    </Typography>

                    <br />

                    <Table>

                        <TableHead>
                            <TableRow>

                                <TableCell>
                                    <b>ID</b>
                                </TableCell>

                                <TableCell>
                                    <b>Device Name</b>
                                </TableCell>

                                <TableCell>
                                    <b>Type</b>
                                </TableCell>

                                <TableCell>
                                    <b>IMEI</b>
                                </TableCell>

                                <TableCell>
                                    <b>Status</b>
                                </TableCell>

                                <TableCell>
                                    <b>Location</b>
                                </TableCell>

                                <TableCell>
                                    <b>Actions</b>
                                </TableCell>

                            </TableRow>
                        </TableHead>

                        <TableBody>

                            {devices.map((device) => (

                                <TableRow key={device.id}>

                                    <TableCell>
                                        {device.id}
                                    </TableCell>

                                    <TableCell>
                                        {device.name}
                                    </TableCell>

                                    <TableCell>
                                        {device.type}
                                    </TableCell>

                                    <TableCell>
                                        {device.imei}
                                    </TableCell>

                                    <TableCell>
                                        {device.status}
                                    </TableCell>

                                    <TableCell>
                                        {device.location}
                                    </TableCell>

                                    <TableCell>

                                        <Button
                                            size="small"
                                            color="warning"
                                            variant="contained"
                                            sx={{ mr: 1 }}
                                            onClick={() =>
                                                toggleStatus(device.id)
                                            }
                                        >
                                            Status
                                        </Button>

                                        <Button
                                            size="small"
                                            color="error"
                                            variant="contained"
                                            onClick={() =>
                                                deleteDevice(device.id)
                                            }
                                        >
                                            Delete
                                        </Button>

                                    </TableCell>

                                </TableRow>

                            ))}

                        </TableBody>

                    </Table>

                </CardContent>
            </Card>

        </Layout>
    );
}

export default Devices;
